"""
activation_functions.py
Demonstrates manual implementation, PyTorch built-ins, and gradient checks.
Run with: python activation_functions.py
"""
import torch
import torch.nn as nn
import torch.nn.functional as F
import math


# ── 1. Manual implementations (for understanding) ─────────────────────────

def sigmoid_manual(z: torch.Tensor) -> torch.Tensor:
    return 1.0 / (1.0 + torch.exp(-z))

def tanh_manual(z: torch.Tensor) -> torch.Tensor:
    e_pos = torch.exp(z)
    e_neg = torch.exp(-z)
    return (e_pos - e_neg) / (e_pos + e_neg)

def relu_manual(z: torch.Tensor) -> torch.Tensor:
    return torch.clamp(z, min=0.0)

def leaky_relu_manual(z: torch.Tensor, alpha: float = 0.01) -> torch.Tensor:
    return torch.where(z > 0, z, alpha * z)

def gelu_manual(z: torch.Tensor) -> torch.Tensor:
    """Fast GELU approximation used in Transformers."""
    return 0.5 * z * (
        1.0 + torch.tanh(math.sqrt(2.0 / math.pi) * (z + 0.044715 * z ** 3))
    )

def softmax_stable(z: torch.Tensor, dim: int = -1) -> torch.Tensor:
    """Numerically stable softmax: subtract max to prevent overflow."""
    z_shifted = z - z.max(dim=dim, keepdim=True).values
    exp_z = torch.exp(z_shifted)
    return exp_z / exp_z.sum(dim=dim, keepdim=True)


# ── 2. Verify manual implementations match PyTorch built-ins ──────────────

def verify_implementations():
    torch.manual_seed(0)
    z = torch.randn(4, 8)

    checks = [
        ("sigmoid",  sigmoid_manual(z),               torch.sigmoid(z)),
        ("tanh",     tanh_manual(z),                  torch.tanh(z)),
        ("relu",     relu_manual(z),                  F.relu(z)),
        ("leaky",    leaky_relu_manual(z, 0.01),      F.leaky_relu(z, 0.01)),
        ("gelu",     gelu_manual(z),                  F.gelu(z, approximate='tanh')),
        ("softmax",  softmax_stable(z, dim=-1),       F.softmax(z, dim=-1)),
    ]
    for name, manual_out, torch_out in checks:
        max_diff = (manual_out - torch_out).abs().max().item()
        status = "PASS" if max_diff < 1e-5 else "FAIL"
        print(f"  [{status}] {name}: max diff = {max_diff:.2e}")


# ── 3. Build a pluggable MLP ───────────────────────────────────────────────

class MLP(nn.Module):
    def __init__(self, dims: list[int], activation: nn.Module):
        super().__init__()
        layers: list[nn.Module] = []
        for i in range(len(dims) - 1):
            layers.append(nn.Linear(dims[i], dims[i + 1]))
            if i < len(dims) - 2:
                layers.append(activation)
        self.net = nn.Sequential(*layers)
        self._apply_init(activation)

    def _apply_init(self, activation: nn.Module):
        nonlinearity = (
            'relu' if isinstance(activation, (nn.ReLU, nn.LeakyReLU))
            else 'linear'
        )
        for m in self.modules():
            if isinstance(m, nn.Linear):
                if nonlinearity == 'relu':
                    nn.init.kaiming_normal_(m.weight, nonlinearity='relu')
                else:
                    nn.init.xavier_normal_(m.weight)
                nn.init.zeros_(m.bias)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.net(x)


# ── 4. Gradient flow check ─────────────────────────────────────────────────

def check_gradient_flow(model: nn.Module, x: torch.Tensor, y: torch.Tensor):
    criterion = nn.MSELoss()
    out = model(x)
    loss = criterion(out, y)
    loss.backward()
    dead, total = 0, 0
    for name, param in model.named_parameters():
        if param.grad is not None:
            mean_grad = param.grad.abs().mean().item()
            print(f"    {name:30s} mean|grad| = {mean_grad:.4e}")
        else:
            print(f"    {name:30s} NO GRADIENT")
    model.zero_grad()


if __name__ == "__main__":
    print("=== Verifying manual implementations ===")
    verify_implementations()

    torch.manual_seed(42)
    x = torch.randn(16, 32)
    y = torch.randn(16, 4)

    for act_name, act in [
        ("ReLU",       nn.ReLU()),
        ("GELU",       nn.GELU(approximate='tanh')),
        ("Sigmoid",    nn.Sigmoid()),
        ("Tanh",       nn.Tanh()),
        ("Leaky ReLU", nn.LeakyReLU(0.01)),
    ]:
        print(f"\n=== Gradient flow: 6-layer MLP with {act_name} ===")
        model = MLP([32, 64, 64, 64, 64, 64, 4], activation=act)
        check_gradient_flow(model, x, y)
